function solve(nums: number[], queries: number[][]): number[] {
    const n = nums.length;
    const ans: number[] = [];

    // Preprocess the array to create a frequency map for each index
    // We'll use a 2D array where freq[i][num] is the frequency of num in nums[0..i]
    // But since nums can be large, we'll use a map for each index
    const freqMap: Map<number, Map<number, number>>[] = new Array(n).fill(null).map(() => new Map());

    for (let i = 0; i < n; i++) {
        const currentNum = nums[i];
        const currentMap = new Map(freqMap[i] || new Map());
        currentMap.set(currentNum, (currentMap.get(currentNum) || 0) + 1);
        freqMap[i] = currentMap;
    }

    for (const [l, r, threshold] of queries) {
        const subArr = nums.slice(l, r + 1);
        const freq = new Map<number, number>();

        for (const num of subArr) {
            freq.set(num, (freq.get(num) || 0) + 1);
        }

        let maxFreq = -1;
        let result: number | null = null;

        for (const [num, count] of freq.entries()) {
            if (count >= threshold) {
                if (count > maxFreq || (count === maxFreq && num < result)) {
                    maxFreq = count;
                    result = num;
                }
            }
        }

        ans.push(result !== null ? result : -1);
    }

    return ans;
}

